from fib import fib

def test_fib_base_cases():
    assert fib(0) == 0
    assert fib(1) == 1

def test_fib_small():
    assert fib(2) == 1
    assert fib(3) == 2
    assert fib(5) == 5

def test_fib_10():
    assert fib(10) == 55

from parens import is_balanced

def test_simple():
    assert is_balanced('()') is True
    assert is_balanced('()[]{}') is True

def test_nested():
    assert is_balanced('{[()]}') is True
    assert is_balanced('([{}])') is True

def test_unbalanced():
    assert is_balanced('(]') is False
    assert is_balanced('([)]') is False
    assert is_balanced('{') is False

def test_empty():
    assert is_balanced('') is True

def test_with_other_chars():
    assert is_balanced('hello (world) [!]') is True
    assert is_balanced('a + b * (c - d') is False
